                    if spec.ty == Ty::Int {
                        writeln!(
                            out,
                            "  }}}}\n  return sembla_add_i64(partials[0], partials[1], error);\n}}"
                        )
                        .unwrap();
                    } else {
                        writeln!(out, "  }}}}\n  return partials[0] + partials[1];\n}}").unwrap();
                    }
                }
            }
        }
        Ok(())
    }

