        }
        out.push_str("}\n");
        out.push_str("\nextern \"C\" __global__ void sembla_build_output_partials(const unsigned char* state, const unsigned long long* column_offsets, const unsigned long long* row_counts, const unsigned char* inputs, const unsigned long long* input_offsets, const unsigned long long* input_counts, const unsigned char* params, const unsigned char* aggs, const unsigned long long* agg_offsets, unsigned long long* output_partials, unsigned char* output_errors) {\n  unsigned long long slot = (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;\n  unsigned char local_error = 0; unsigned char* error = &local_error;\n");
        for wire in &self.model.model().wires {
            let from_box = self
                .model
                .model()
                .boxes
                .iter()
                .position(|entry| entry.name == wire.from.r#box)
                .ok_or_else(|| codegen("wire source box disappeared"))?;
            let to_box = self
                .model
                .model()
                .boxes
                .iter()
                .position(|entry| entry.name == wire.to.r#box)
                .ok_or_else(|| codegen("wire target box disappeared"))?;
            let output = self.model.model().boxes[from_box]
                .outputs
                .iter()
                .find(|entry| entry.name == wire.from.port)
                .ok_or_else(|| codegen("wire output disappeared"))?;
            let to_port_index = self.port_index(to_box, &wire.to.port)?;
            let sembla_ir::OutputBuilder::PerTable { table, fields } = &output.builder;
            let table_index = self.table_index(from_box, table)?;
            let global_table = self.global_table(from_box, table_index);
            let rows = Rows::State {
                box_index: from_box,
                table_index,
            };
            for (field_index, field) in fields.iter().enumerate() {
                let target_field = self.input_field(to_box, to_port_index, field_index);
                let ty = Ty::from(&output.schema[field_index].ty);
                writeln!(out, "  if (slot == {}ULL || slot == {}ULL) {{ unsigned int part = (unsigned int)(slot - {}ULL); {} result = ({})0; unsigned long long midpoint = row_counts[{global_table}] / 2ULL; unsigned long long begin = part == 0U ? 0ULL : midpoint; unsigned long long end = part == 0U ? midpoint : row_counts[{global_table}];", target_field * 2, target_field * 2 + 1, target_field * 2, ty.cuda(), ty.cuda()).unwrap();
                writeln!(out, "    for (unsigned long long row = begin; row < end; ++row) {{ local_error = 0;").unwrap();
                let selected = if let Some(filter) = &field.filter {
                    self.render(filter, rows, Some(&Ty::Bool), "state", "row")?
                        .0
                } else {
                    "1".to_owned()
                };
                match &field.op {
                    AggOp::Count => writeln!(out, "      int selected = {selected}; if (selected) result = sembla_add_i64(result, 1LL, error);").unwrap(),
                    AggOp::Sum { value } => {
                        let value = self.render(value, rows, Some(&ty), "state", "row")?.0;
                        writeln!(out, "      int selected = {selected}; {} value = ({})({value});", ty.cuda(), ty.cuda()).unwrap();
