   453	    fn infer(&self, expr: &Expr, rows: Rows, expected: Option<&Ty>) -> Result<Ty, CudaError> {
   454	        match expr {
   455	            Expr::Real { .. } => Ok(Ty::Real),
   456	            Expr::Int { .. } => Ok(Ty::Int),
   457	            Expr::Bool { .. } => Ok(Ty::Bool),
   458	            Expr::Enum { variant } => match expected {
   459	                Some(Ty::Enum(variants)) if variants.iter().any(|item| item == variant) => {
   460	                    Ok(Ty::Enum(variants.clone()))
   461	                }
   462	                _ => Err(codegen(format!(
   463	                    "enum literal '{variant}' lacks destination enum context"
   464	                ))),
   465	            },
   466	            Expr::Param { name } => self
   467	                .model
   468	                .model()
   469	                .params
   470	                .iter()
   471	                .find(|parameter| parameter.name == *name)
   472	                .map(|parameter| match parameter.ty {
   473	                    ParamType::Real => Ty::Real,
   474	                    ParamType::Int => Ty::Int,
   475	                })
   476	                .ok_or_else(|| codegen(format!("unknown parameter '{name}'"))),
   477	            Expr::SelfAttr { name } => self.row_attr(rows, name).map(|attr| Ty::from(&attr.ty)),
   478	            Expr::Add { lhs, rhs } | Expr::Sub { lhs, rhs } | Expr::Mul { lhs, rhs } => {
   479	                let left = self.infer(lhs, rows, None)?;
   480	                let right = self.infer(rhs, rows, None)?;
   481	                if !left.numeric() || !right.numeric() {
   482	                    return Err(codegen("arithmetic operand is not numeric"));
   483	                }
   484	                if left == Ty::Real || right == Ty::Real {
   485	                    Ok(Ty::Real)
   486	                } else {
   487	                    Ok(Ty::Int)
   488	                }
   489	            }
   490	            Expr::Div { lhs, rhs } => {
   491	                if !self.infer(lhs, rows, None)?.numeric()
   492	                    || !self.infer(rhs, rows, None)?.numeric()
   493	                {
   494	                    return Err(codegen("division operand is not numeric"));
   495	                }
   496	                Ok(Ty::Real)
   497	            }
   498	            Expr::Eq { .. }
   499	            | Expr::Ne { .. }
   500	            | Expr::Lt { .. }
   501	            | Expr::Le { .. }
   502	            | Expr::Gt { .. }
   503	            | Expr::Ge { .. }
   504	            | Expr::And { .. }
   505	            | Expr::Or { .. }
   506	            | Expr::Not { .. }
   507	            | Expr::EnumIs { .. } => Ok(Ty::Bool),
   508	            Expr::Input { port, agg } => {
   509	                let key = format!("{}:{port}:{agg:?}", rows_box(rows));
   510	                self.inputs
   511	                    .iter()
   512	                    .find(|entry| entry.key == key)
   513	                    .map(|entry| entry.ty.clone())
   514	                    .ok_or_else(|| codegen("input aggregate was not collected"))
   515	            }
   516	            Expr::Agg { .. } => {
   517	                let (box_index, table_index) = rows_state(rows)?;
   518	                let key = format!("{box_index}:{table_index}:{expr:?}");
   519	                self.aggs
   520	                    .iter()
   521	                    .find(|entry| entry.key == key)
   522	                    .map(|entry| entry.ty.clone())
   523	                    .ok_or_else(|| codegen("group aggregate was not collected"))
   524	            }
   525	        }
   526	    }
