   533	            } => self.model.model().boxes[box_index].tables[table_index]
   534	                .attrs
   535	                .iter()
   536	                .find(|attr| attr.name == name)
   537	                .ok_or_else(|| codegen(format!("unknown state attribute '{name}'"))),
   538	            Rows::Input {
   539	                box_index,
   540	                port_index,
   541	            } => self.model.model().boxes[box_index].inputs[port_index]
   542	                .schema
   543	                .iter()
