   549	    fn render(
   550	        &self,
   551	        expr: &Expr,
   552	        rows: Rows,
   553	        expected: Option<&Ty>,
   554	        state_name: &str,
   555	        row_name: &str,
   556	    ) -> Result<(String, Ty), CudaError> {
   557	        let result = match expr {
   558	            Expr::Real { value } => (f64_literal(*value), Ty::Real),
   559	            Expr::Int { value } => (i64_literal(*value), Ty::Int),
   560	            Expr::Bool { value } => ((if *value { "1" } else { "0" }).to_owned(), Ty::Bool),
   561	            Expr::Enum { variant } => {
   562	                let Ty::Enum(variants) = expected.ok_or_else(|| {
   563	                    codegen(format!(
   564	                        "enum literal '{variant}' lacks destination context"
   565	                    ))
   566	                })?
   567	                else {
   568	                    return Err(codegen("enum literal destination is not Enum"));
   569	                };
   570	                let index = variants
   571	                    .iter()
   572	                    .position(|item| item == variant)
   573	                    .ok_or_else(|| codegen(format!("unknown enum variant '{variant}'")))?;
   574	                (format!("{index}U"), Ty::Enum(variants.clone()))
   575	            }
   576	            Expr::Param { name } => {
   577	                let index = *self
   578	                    .params
   579	                    .get(name)
   580	                    .ok_or_else(|| codegen(format!("unknown parameter '{name}'")))?;
   581	                let ty = self.infer(expr, rows, expected)?;
   582	                (
   583	                    format!("(*((const {}*)(params + {}ULL)))", ty.cuda(), index * 8),
   584	                    ty,
   585	                )
   586	            }
   587	            Expr::SelfAttr { name } => self.render_attr(rows, name, state_name, row_name)?,
   588	            Expr::Add { lhs, rhs } | Expr::Sub { lhs, rhs } | Expr::Mul { lhs, rhs } => {
   589	                let (left, left_ty) = self.render(lhs, rows, None, state_name, row_name)?;
   590	                let (right, right_ty) = self.render(rhs, rows, None, state_name, row_name)?;
   591	                let ty = if left_ty == Ty::Real || right_ty == Ty::Real {
   592	                    Ty::Real
   593	                } else {
   594	                    Ty::Int
   595	                };
   596	                if ty == Ty::Int {
   597	                    let helper = match expr {
   598	                        Expr::Add { .. } => "sembla_add_i64",
   599	                        Expr::Sub { .. } => "sembla_sub_i64",
   600	                        Expr::Mul { .. } => "sembla_mul_i64",
   601	                        _ => unreachable!(),
   602	                    };
   603	                    (format!("{helper}({left}, {right}, error)"), ty)
   604	                } else {
   605	                    let operator = match expr {
   606	                        Expr::Add { .. } => "+",
   607	                        Expr::Sub { .. } => "-",
   608	                        Expr::Mul { .. } => "*",
   609	                        _ => unreachable!(),
   610	                    };
   611	                    (
   612	                        format!("((double)({left}) {operator} (double)({right}))"),
   613	                        ty,
   614	                    )
   615	                }
   616	            }
   617	            Expr::Div { lhs, rhs } => {
   618	                let (left, _) = self.render(lhs, rows, None, state_name, row_name)?;
   619	                let (right, _) = self.render(rhs, rows, None, state_name, row_name)?;
   620	                (format!("((double)({left}) / (double)({right}))"), Ty::Real)
   621	            }
   622	            Expr::Eq { lhs, rhs }
   623	            | Expr::Ne { lhs, rhs }
   624	            | Expr::Lt { lhs, rhs }
   625	            | Expr::Le { lhs, rhs }
   626	            | Expr::Gt { lhs, rhs }
   627	            | Expr::Ge { lhs, rhs } => {
   628	                let left_hint = self.infer(lhs, rows, None).ok();
   629	                let right_hint = self.infer(rhs, rows, left_hint.as_ref()).ok();
   630	                let (left, left_ty) =
   631	                    self.render(lhs, rows, right_hint.as_ref(), state_name, row_name)?;
   632	                let (right, right_ty) =
   633	                    self.render(rhs, rows, Some(&left_ty), state_name, row_name)?;
   634	                let input_ordering = matches!(rows, Rows::Input { .. })
   635	                    && matches!(
   636	                        expr,
   637	                        Expr::Lt { .. } | Expr::Le { .. } | Expr::Gt { .. } | Expr::Ge { .. }
   638	                    );
   639	                let promote_numeric = left_ty.numeric()
   640	                    && right_ty.numeric()
   641	                    && (left_ty == Ty::Real || right_ty == Ty::Real || input_ordering);
   642	                let left = if promote_numeric {
   643	                    format!("(double)({left})")
   644	                } else {
   645	                    left
   646	                };
   647	                let right = if promote_numeric {
   648	                    format!("(double)({right})")
   649	                } else {
   650	                    right
   651	                };
   652	                let operator = match expr {
   653	                    Expr::Eq { .. } => "==",
   654	                    Expr::Ne { .. } => "!=",
   655	                    Expr::Lt { .. } => "<",
   656	                    Expr::Le { .. } => "<=",
   657	                    Expr::Gt { .. } => ">",
   658	                    Expr::Ge { .. } => ">=",
   659	                    _ => unreachable!(),
   660	                };
   661	                (format!("(({left}) {operator} ({right}))"), Ty::Bool)
   662	            }
   663	            Expr::And { lhs, rhs } | Expr::Or { lhs, rhs } => {
   664	                let (left, _) = self.render(lhs, rows, Some(&Ty::Bool), state_name, row_name)?;
   665	                let (right, _) = self.render(rhs, rows, Some(&Ty::Bool), state_name, row_name)?;
   666	                let operator = if matches!(expr, Expr::And { .. }) {
   667	                    "&"
   668	                } else {
   669	                    "|"
   670	                };
   671	                (format!("(({left}) {operator} ({right}))"), Ty::Bool)
   672	            }
   673	            Expr::Not { expr } => {
   674	                let (value, _) = self.render(expr, rows, Some(&Ty::Bool), state_name, row_name)?;
   675	                (format!("(!({value}))"), Ty::Bool)
   676	            }
   677	            Expr::EnumIs { attr, variant } => {
   678	                let attr_decl = self.row_attr(rows, attr)?;
   679	                let AttrType::Enum { variants } = &attr_decl.ty else {
   680	                    return Err(codegen("enum_is attribute is not Enum"));
   681	                };
   682	                let index = variants
   683	                    .iter()
   684	                    .position(|item| item == variant)
   685	                    .ok_or_else(|| codegen(format!("unknown enum variant '{variant}'")))?;
   686	                let (value, _) = self.render_attr(rows, attr, state_name, row_name)?;
   687	                (format!("(({value}) == {index}U)"), Ty::Bool)
   688	            }
   689	            Expr::Input { port, agg } => {
   690	                let box_index = rows_box(rows);
   691	                let key = format!("{box_index}:{port}:{agg:?}");
   692	                let index = self
   693	                    .inputs
   694	                    .iter()
   695	                    .position(|entry| entry.key == key)
   696	                    .ok_or_else(|| codegen("input aggregate was not collected"))?;
   697	                (
   698	                    format!(
   699	                        "sembla_input_{index}(inputs, input_offsets, input_counts, params, error)"
   700	                    ),
   701	                    self.inputs[index].ty.clone(),
   702	                )
   703	            }
   704	            Expr::Agg { .. } => {
   705	                let (box_index, table_index) = rows_state(rows)?;
   706	                let key = format!("{box_index}:{table_index}:{expr:?}");
   707	                let index = self
   708	                    .aggs
   709	                    .iter()
   710	                    .position(|entry| entry.key == key)
   711	                    .ok_or_else(|| codegen("group aggregate was not collected"))?;
   712	                let spec = &self.aggs[index];
   713	                let query = &self.model.model().boxes[box_index].tables[table_index];
   714	                let attr = &query.attrs[spec.self_fk_column];
   715	                let (group, _) = self.render_attr(rows, &attr.name, state_name, row_name)?;
   716	                (
   717	                    format!(
   718	                        "(*((const {}*)(aggs + agg_offsets[{index}]) + (unsigned long long)({group})))",
   719	                        spec.ty.cuda()
   720	                    ),
   721	                    spec.ty.clone(),
   722	                )
   723	            }
   724	        };
   725	        Ok(result)
   726	    }
