   775	    fn emit(self) -> Result<GeneratedCuda, CudaError> {
   776	        let mut out = String::new();
   777	        writeln!(
   778	            out,
   779	            "// Generated by sembla-cuda {}. DO NOT EDIT.",
   780	            env!("CARGO_PKG_VERSION")
   781	        )
   782	        .unwrap();
   783	        writeln!(out, "// model: {}", self.model.model().name).unwrap();
   784	        out.push_str(PRELUDE);
   785	        self.emit_input_helpers(&mut out)?;
   786	        self.emit_aggregate_kernel(&mut out)?;
   787	        let transition_kernels = self.emit_transition_kernels(&mut out)?;
   788	        self.emit_error_check_kernel(&mut out);
   789	        self.emit_resolve_kernel(&mut out)?;
   790	        self.emit_apply_kernel(&mut out)?;
   791	        self.emit_output_kernel(&mut out)?;
   792	        out.push_str(PHILOX_TEST_KERNEL);
   793	        let source_sha256 = hex(Sha256::digest(out.as_bytes()).as_slice());
   794	        let aggregate_group_tables = self
   795	            .aggs
   796	            .iter()
   797	            .map(|spec| self.global_table(spec.box_index, spec.group_table_index))
   798	            .collect();
   799	        let schedule_aggregate_indices = self
   800	            .aggs
   801	            .iter()
   802	            .enumerate()
   803	            .filter_map(|(index, spec)| spec.schedule_use.then_some(index))
   804	            .collect();
   805	        let effect_aggregate_indices = self
   806	            .aggs
   807	            .iter()
   808	            .enumerate()
   809	            .filter_map(|(index, spec)| {
   810	                (!spec.schedule_use && !spec.effect_rules.is_empty()).then_some(index)
   811	            })
   812	            .collect();
   813	        let output_aggregate_indices = self
   814	            .aggs
   815	            .iter()
   816	            .enumerate()
   817	            .filter_map(|(index, spec)| spec.output_use.then_some(index))
   818	            .collect();
   819	        Ok(GeneratedCuda {
   820	            source: out,
   821	            source_sha256,
   822	            transition_kernels,
   823	            aggregate_group_tables,
   824	            schedule_aggregate_indices,
   825	            effect_aggregate_indices,
   826	            output_aggregate_indices,
   827	        })
   828	    }
