   830	    fn emit_input_helpers(&self, out: &mut String) -> Result<(), CudaError> {
   831	        for (index, spec) in self.inputs.iter().enumerate() {
   832	            writeln!(out, "__device__ __forceinline__ {} sembla_input_{index}(const unsigned char* inputs, const unsigned long long* input_offsets, const unsigned long long* input_counts, const unsigned char* params, unsigned char* error) {{", spec.ty.cuda()).unwrap();
   833	            let port = self.port(spec.box_index, spec.port_index);
   834	            match &spec.agg.op {
