734	    ) -> Result<(String, Ty), CudaError> {
735	        match rows {
736	            Rows::State {
737	                box_index,
738	                table_index,
739	            } => {
740	                let table = &self.model.model().boxes[box_index].tables[table_index];
741	                let index = attr_index(table, name)?;
742	                let ty = Ty::from(&table.attrs[index].ty);
743	                let column = self.column(box_index, table_index, index);
744	                Ok((
745	                    format!(
746	                        "(*((const {}*)({state_name} + column_offsets[{column}]) + (unsigned long long)({row_name})))",
747	                        ty.cuda()
748	                    ),
749	                    ty,
750	                ))
751	            }
752	            Rows::Input {
753	                box_index,
754	                port_index,
755	            } => {
756	                let port = &self.model.model().boxes[box_index].inputs[port_index];
757	                let index = port
758	                    .schema
759	                    .iter()
760	                    .position(|attr| attr.name == name)
761	                    .ok_or_else(|| codegen(format!("unknown input attribute '{name}'")))?;
762	                let ty = Ty::from(&port.schema[index].ty);
763	                let field = self.input_field(box_index, port_index, index);
764	                Ok((
765	                    format!(
766	                        "(*((const {}*)(inputs + input_offsets[{field}]) + (unsigned long long)({row_name})))",
767	                        ty.cuda()
768	                    ),
769	                    ty,
770	                ))
771	            }
772	        }
