   900	                            TickError::Evaluation(
   901	                                "output integer sum overflow while merging partials".to_owned(),
   902	                            )
   903	                        })?;
   904	                        ColumnData::Int(vec![sum])
   905	                    }
   906	                    other => return Err(runtime_type("output Sum", &other)),
   907	                }
   908	            }
   909	        };
   910	        columns.push(column);
