   935	fn eval_input_aggregate(
   936	    input: &InputTable,
   937	    agg: &Aggregate,
   938	    params: &ParamEnv,
   939	    result_rows: usize,
   940	    result_type: &RuntimeType,
   941	) -> Result<InternalColumn, EvalError> {
   942	    let mut selected = Vec::with_capacity(input.row_count);
   943	    for row in 0..input.row_count {
   944	        let keep = match &agg.filter {
   945	            Some(filter) => match eval_input_scalar(filter, input, row, params)? {
   946	                InputScalar::Bool(value) => value,
   947	                _ => return Err(EvalError::new("input aggregate filter is not Bool")),
   948	            },
   949	            None => true,
   950	        };
   951	        selected.push(keep);
   952	    }
   953	    match &agg.op {
   954	        AggOp::Count => {
   955	            let count = selected.iter().filter(|value| **value).count();
   956	            let count = i64::try_from(count)
   957	                .map_err(|_| EvalError::new("input aggregate count exceeds i64"))?;
