   252	/// Executes ticks `0..n_ticks` and records strict saturation warnings.
   253	pub fn run(
   254	    model: &ValidatedModel,
   255	    state: &mut StateStore,
   256	    params: &ParamEnv,
   257	    seed: u64,
   258	    n_ticks: u32,
   259	) -> Result<RunReport, TickError> {
   260	    let mut ticks = Vec::with_capacity(n_ticks as usize);
