   265	            let fired_count = outcome
   266	                .fired_per_resource_table
   267	                .iter()
   268	                .find(|(name, _)| name == table)
   269	                .map_or(0, |(_, count)| *count);
   270	            if exceeds_saturation_threshold(*deferred_count, fired_count) {
   271	                let warning = SaturationWarning {
