   863	                match eval_column(value, eval_table, snapshot, params, &mut cache)? {
   864	                    ValueColumn::Real(values) => {
   865	                        // Match the fixed two-part Level-A CUDA reduction.
   866	                        let midpoint = values.len() / 2;
   867	                        let mut partials = [0.0_f64; 2];
   868	                        for (partial, range) in [0..midpoint, midpoint..values.len()]
   869	                            .into_iter()
   870	                            .enumerate()
   871	                        {
   872	                            for row in range {
   873	                                if selected[row] {
   874	                                    partials[partial] += values[row];
   875	                                }
   876	                            }
   877	                        }
   878	                        ColumnData::Real(vec![partials[0] + partials[1]])
   879	                    }
   880	                    ValueColumn::Int(values) => {
   881	                        let midpoint = values.len() / 2;
   882	                        let mut partials = [0_i64; 2];
   883	                        for (partial, range) in [0..midpoint, midpoint..values.len()]
   884	                            .into_iter()
   885	                            .enumerate()
