   959	        }
   960	        AggOp::Sum { value } => {
   961	            // Level-A schedule shared with CUDA: ascending rows in two fixed
   962	            // contiguous halves, then partial 0 followed by partial 1.
   963	            let midpoint = input.row_count / 2;
   964	            match result_type {
   965	                RuntimeType::Real => {
   966	                    let mut partials = [0.0_f64; 2];
   967	                    for (partial, range) in [0..midpoint, midpoint..input.row_count]
   968	                        .into_iter()
   969	                        .enumerate()
   970	                    {
   971	                        for row in range {
   972	                            if !selected[row] {
   973	                                continue;
   974	                            }
   975	                            match eval_input_scalar(value, input, row, params)? {
   976	                                InputScalar::Int(value) => partials[partial] += value as f64,
   977	                                InputScalar::Real(value) => partials[partial] += value,
   978	                                _ => {
   979	                                    return Err(EvalError::new(
   980	                                        "input aggregate Sum value is not numeric",
   981	                                    ))
   982	                                }
   983	                            }
   984	                        }
   985	                    }
   986	                    Ok(InternalColumn::Real(vec![
   987	                        partials[0] + partials[1];
   988	                        result_rows
   989	                    ]))
   990	                }
   991	                RuntimeType::Int => {
   992	                    let mut partials = [0_i64; 2];
