   252	/// Executes ticks `0..n_ticks` and records strict saturation warnings.
   253	pub fn run(
   254	    model: &ValidatedModel,
   255	    state: &mut StateStore,
   256	    params: &ParamEnv,
   257	    seed: u64,
   258	    n_ticks: u32,
   259	) -> Result<RunReport, TickError> {
   260	    let mut ticks = Vec::with_capacity(n_ticks as usize);
   261	    let mut warnings = Vec::new();
   262	    for tick in 0..n_ticks {
   263	        let outcome = execute_tick(model, state, params, seed, tick)?;
   264	        for (table, deferred_count) in &outcome.report.deferred_per_resource_table {
   265	            let fired_count = outcome
   266	                .fired_per_resource_table
   267	                .iter()
   268	                .find(|(name, _)| name == table)
   269	                .map_or(0, |(_, count)| *count);
   270	            if exceeds_saturation_threshold(*deferred_count, fired_count) {
   271	                let warning = SaturationWarning {
   272	                    tick,
   273	                    table: table.clone(),
   274	                    deferred_count: *deferred_count,
   275	                    fired_count,
   276	                };
   277	                eprintln!(
   278	                    "warning: tick {} resource table '{}': {} deferred exceeds 10% of {} fired",
   279	                    warning.tick, warning.table, warning.deferred_count, warning.fired_count
   280	                );
   281	                warnings.push(warning);
   282	            }
   283	        }
   284	        ticks.push(outcome.report);
   285	    }
   286	    let summaries = summarize(model, &ticks)?;
   287	    Ok(RunReport {
   288	        ticks,
   289	        summaries,
   290	        warnings,
   291	    })
   292	}
