376	    pub fn run(&mut self, ticks: u32) -> Result<CudaRunResult, CudaError> {
377	        let mut per_tick_state_hashes = if self.hash_mode == HashMode::EveryTick {
378	            Vec::with_capacity(ticks as usize)
379	        } else {
380	            Vec::new()
381	        };
382	        for _ in 0..ticks {
383	            self.execute_tick()?;
384	            if self.hash_mode == HashMode::EveryTick {
385	                per_tick_state_hashes.push(self.download_hash()?);
386	            }
387	        }
388	        let final_state_hash = match per_tick_state_hashes.last() {
389	            Some(hash) => *hash,
390	            None => self.download_hash()?,
391	        };
392	        Ok(CudaRunResult {
393	            final_state_hash,
394	            per_tick_state_hashes,
395	        })
396	    }
