 213	    fn collect_all(&mut self) -> Result<(), CudaError> {
 214	        for validated in self.model.transitions() {
 215	            let box_index = validated.box_index;
 216	            let transition =
 217	                &self.model.model().boxes[box_index].transitions[validated.transition_index];
 218	            let table_index = self.table_index(box_index, &transition.table)?;
 219	            self.collect_expr(box_index, table_index, &transition.guard, AggUse::Schedule)?;
 220	            self.collect_expr(box_index, table_index, &transition.hazard, AggUse::Schedule)?;
 221	            for effect in &transition.effects {
 222	                let Effect::SetAttr { value, .. } = effect;
 223	                self.collect_expr(
 224	                    box_index,
 225	                    table_index,
 226	                    value,
 227	                    AggUse::Effect(validated.rule_id),
 228	                )?;
 229	            }
 230	            for claim in &transition.contests {
 231	                self.collect_expr(box_index, table_index, &claim.resource, AggUse::Schedule)?;
 232	                if let ClaimOrdering::Key { expr } = &claim.ordering {
 233	                    self.collect_expr(box_index, table_index, expr, AggUse::Schedule)?;
 234	                }
 235	            }
 236	        }
 237	
 238	        // Only wired outputs are observable and evaluated by the CPU oracle.
 239	        for wire in &self.model.model().wires {
 240	            let box_index = self
 241	                .model
 242	                .model()
 243	                .boxes
 244	                .iter()
 245	                .position(|model_box| model_box.name == wire.from.r#box)
 246	                .expect("validated output box is indexed");
 247	            let model_box = &self.model.model().boxes[box_index];
 248	            let output = model_box
 249	                .outputs
 250	                .iter()
 251	                .find(|output| output.name == wire.from.port)
 252	                .expect("validated output is indexed");
 253	            let sembla_ir::OutputBuilder::PerTable { table, fields } = &output.builder;
 254	            let table_index = self.table_index(box_index, table)?;
 255	            for field in fields {
 256	                if let Some(filter) = &field.filter {
 257	                    self.collect_expr(box_index, table_index, filter, AggUse::Output)?;
 258	                }
 259	                if let AggOp::Sum { value } = &field.op {
 260	                    self.collect_expr(box_index, table_index, value, AggUse::Output)?;
 261	                }
 262	            }
 263	        }
 264	        Ok(())
 265	    }
