 267	    fn collect_expr(
 268	        &mut self,
 269	        box_index: usize,
 270	        query_table_index: usize,
 271	        expr: &Expr,
 272	        usage: AggUse,
 273	    ) -> Result<(), CudaError> {
 274	        match expr {
 275	            Expr::Add { lhs, rhs }
 276	            | Expr::Sub { lhs, rhs }
 277	            | Expr::Mul { lhs, rhs }
 278	            | Expr::Div { lhs, rhs }
 279	            | Expr::Eq { lhs, rhs }
 280	            | Expr::Ne { lhs, rhs }
 281	            | Expr::Lt { lhs, rhs }
 282	            | Expr::Le { lhs, rhs }
 283	            | Expr::Gt { lhs, rhs }
 284	            | Expr::Ge { lhs, rhs }
 285	            | Expr::And { lhs, rhs }
 286	            | Expr::Or { lhs, rhs } => {
 287	                self.collect_expr(box_index, query_table_index, lhs, usage)?;
 288	                self.collect_expr(box_index, query_table_index, rhs, usage)?;
 289	            }
 290	            Expr::Not { expr } => self.collect_expr(box_index, query_table_index, expr, usage)?,
 291	            Expr::Input { port, agg } => {
 292	                if let Some(filter) = &agg.filter {
 293	                    Self::validate_input_expr(filter)?;
 294	                }
 295	                if let AggOp::Sum { value } = &agg.op {
 296	                    Self::validate_input_expr(value)?;
 297	                }
 298	                let key = format!("{box_index}:{port}:{agg:?}");
 299	                if !self.inputs.iter().any(|entry| entry.key == key) {
 300	                    let port_index = self.port_index(box_index, port)?;
 301	                    let ty = match &agg.op {
 302	                        AggOp::Count => Ty::Int,
 303	                        AggOp::Sum { value } => self.infer(
 304	                            value,
 305	                            Rows::Input {
 306	                                box_index,
 307	                                port_index,
 308	                            },
 309	                            None,
 310	                        )?,
 311	                    };
 312	                    self.inputs.push(InputSpec {
 313	                        key,
 314	                        box_index,
 315	                        port_index,
 316	                        agg: agg.clone(),
 317	                        ty,
 318	                    });
 319	                }
 320	            }
 321	            Expr::Agg {
 322	                op,
 323	                table,
 324	                on,
 325	                filter,
 326	            } => {
 327	                let target_table_index = self.table_index(box_index, table)?;
 328	                self.collect_expr(box_index, target_table_index, filter, usage)?;
 329	                if let AggOp::Sum { value } = op {
 330	                    self.collect_expr(box_index, target_table_index, value, usage)?;
 331	                }
 332	                let key = format!("{box_index}:{query_table_index}:{expr:?}");
 333	                if let Some(existing) = self.aggs.iter_mut().find(|entry| entry.key == key) {
 334	                    existing.record_use(usage);
 335	                } else {
 336	                    let query_table =
 337	                        &self.model.model().boxes[box_index].tables[query_table_index];
 338	                    let target_table =
 339	                        &self.model.model().boxes[box_index].tables[target_table_index];
 340	                    let self_fk_column = attr_index(query_table, &on.self_fk_attr)?;
 341	                    let target_fk_column = attr_index(target_table, &on.fk_attr)?;
 342	                    let group_name = match &query_table.attrs[self_fk_column].ty {
 343	                        AttrType::Ref { table } => table,
 344	                        _ => return Err(codegen("aggregate self key is not Ref")),
 345	                    };
 346	                    let group_table_index = self.table_index(box_index, group_name)?;
 347	                    let ty = match op {
 348	                        AggOp::Count => Ty::Int,
 349	                        AggOp::Sum { value } => self.infer(
 350	                            value,
 351	                            Rows::State {
 352	                                box_index,
 353	                                table_index: target_table_index,
 354	                            },
 355	                            None,
 356	                        )?,
 357	                    };
 358	                    let mut spec = AggSpec {
 359	                        key,
 360	                        box_index,
 361	                        target_table_index,
 362	                        group_table_index,
 363	                        target_fk_column,
 364	                        self_fk_column,
 365	                        op: op.clone(),
 366	                        filter: (**filter).clone(),
 367	                        ty,
 368	                        schedule_use: false,
 369	                        effect_rules: Vec::new(),
 370	                        output_use: false,
 371	                    };
 372	                    spec.record_use(usage);
 373	                    self.aggs.push(spec);
 374	                }
 375	            }
 376	            _ => {}
 377	        }
 378	        Ok(())
 379	    }
