633	fn stage_box(
634	    model: &ValidatedModel,
635	    box_index: usize,
636	    snapshot: &Snapshot<'_>,
637	    params: &ParamEnv,
638	    seed: u64,
639	    tick: u32,
640	) -> Result<BoxOutcome, TickError> {
641	    let model_box = &model.model().boxes[box_index];
642	    let transitions: Vec<_> = model
643	        .transitions()
644	        .iter()
645	        .filter(|transition| transition.box_index == box_index)
646	        .collect();
647	    let mut cache = AggCache::new(model, snapshot, params);
648	    let mut candidates = Vec::new();
649	    for validated in &transitions {
650	        let transition = &model_box.transitions[validated.transition_index];
