662	            ValueColumn::Real(values) => values,
663	            other => return Err(runtime_type("transition hazard", &other)),
664	        };
665	        let mut claim_columns = Vec::with_capacity(transition.contests.len());
666	        for claim in &transition.contests {
667	            let resources =
668	                eval_typed_ref_column(&claim.resource, table, snapshot, params, &mut cache)?;
