674	            let ordering = match &claim.ordering {
675	                ClaimOrdering::RaceTime => None,
676	                ClaimOrdering::Key { expr } => {
677	                    Some(eval_column(expr, table, snapshot, params, &mut cache)?)
678	                }
679	            };
680	            claim_columns.push((resource_table_index, resources.values, ordering, claim));
681	        }
682	        for (row, (guard, lambda)) in guards.into_iter().zip(hazards).enumerate() {
683	            if !guard || lambda.partial_cmp(&0.0) != Some(Ordering::Greater) {
684	                continue;
685	            }
686	            let entity_id = u32::try_from(row).map_err(|_| TickError::EntityIdOverflow {
687	                rule_id: validated.rule_id,
688	                row,
689	            })?;
690	            let race_time = exp_f64(seed, tick, validated.rule_id, entity_id, 0, lambda);
691	            if race_time.partial_cmp(&model.model().dt) != Some(Ordering::Less) {
692	                continue;
693	            }
694	            let mut claims = Vec::with_capacity(claim_columns.len());
695	            for (resource_table, resources, key_column, claim) in &claim_columns {
696	                let ordering = match (&claim.ordering, key_column) {
697	                    (ClaimOrdering::RaceTime, None) => OrderingValue::RaceTime(race_time),
698	                    (ClaimOrdering::Key { expr }, Some(column)) => {
699	                        key_at(column, expr, table_index, model_box, row)?
700	                    }
