717	    }
718	    let resolution = resolve_claims(&candidates, model_box.tables.len(), model_box)?;
719	    let mut pending = Vec::new();
720	    for validated in &transitions {
721	        let transition = &model_box.transitions[validated.transition_index];
722	        let winner_indices: Vec<usize> = candidates
723	            .iter()
724	            .enumerate()
725	            .filter(|(index, candidate)| {
726	                candidate.rule_id == validated.rule_id && resolution.fires[*index]
727	            })
728	            .map(|(index, _)| index)
