739	            let attr_index = schema
740	                .attrs
741	                .iter()
742	                .position(|declaration| declaration.name == *attr)
743	                .expect("validated effect attribute disappeared");
744	            let destination = &schema.attrs[attr_index];
745	            let value = match &destination.ty {
746	                AttrType::Ref { .. } => PendingColumn::Ref(
747	                    eval_typed_ref_column(value, table, snapshot, params, &mut cache)?.values,
748	                ),
749	                _ => PendingColumn::Value(eval_column(
750	                    value,
751	                    table.with_expected_attr(attr)?,
752	                    snapshot,
753	                    params,
754	                    &mut cache,
755	                )?),
756	            };
757	            effect_columns.push((attr_index, value));
758	        }
759	        for candidate_index in winner_indices {
760	            let candidate = &candidates[candidate_index];
760	        let inputs = self
761	            .stream
762	            .memcpy_dtov(&self.inputs)
763	            .map_err(driver_error)?;
764	        let input_counts = self
765	            .stream
766	            .memcpy_dtov(&self.input_counts)
767	            .map_err(driver_error)?;
768	        Ok(hash_state(
769	            &self.model,
770	            &self.layout,
771	            &state,
772	            &inputs,
